parameters.functionCode:
const event = $json;
const history = $json.history || [];
let score = 0;
let reasons = [];

// 1. REAL DEVICE CHECK: Is this specific string new for THIS user?
const knownDevices = history.map(h => h.device);
if (history.length > 0 && !knownDevices.includes(event.device)) {
    score += 3;
    reasons.push("First time using this device");
}

// 2. IMPOSSIBLE TRAVEL CHECK
if (history.length > 0) {
    const last = history[0];
    const timeDiffHours = Math.abs(new Date(event.timestamp || Date.now()) - new Date(last.created_at)) / 36e5;

    if (last.location !== event.location && timeDiffHours < 4) {
        score += 7; // Auto-High
        reasons.push("Impossible Travel: Location changed too fast");
    }
}

// 3. GEOGRAPHIC ANOMALY
if (event.location !== "India") {
    score += 3;
    reasons.push("Access from foreign country");
}

// 4. ACTION SENSITIVITY
if (event.event === "funds_withdrawal" || event.event === "password_change") {
    score += 2;
    reasons.push("Sensitive operation");
}

// FINAL VERDICT
let risk = "LOW";
if (score >= 7) risk = "HIGH";
else if (score >= 3) risk = "MEDIUM";

return [{
    json: {
        ...event,
        rule_score: score,
        rule_risk: risk,
        risk_reasons: reasons.join(", ")
    }
}];

