let content = $json.message.content;

// remove markdown wrapper
content = content
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// parse JSON safely
let ai;
try {
  ai = JSON.parse(content);
} catch (e) {
  throw new Error("AI response parsing failed: " + content);
}

// return merged object (IMPORTANT: preserve existing data)
return [{
  json: {
    ...$json,
    ai_risk: ai.risk_level,
    ai_reason: ai.reason
  }
}];

